document.addEventListener('DOMContentLoaded', function() {
    const projectBriefs = {
        "Campus Sustainability": "The Campus Sustainability initiative is a flagship project aimed at making NIT Kurukshetra a self-reliant and environmentally responsible ecosystem. We are implementing comprehensive waste management, water harvesting, and green infrastructure to create a replicable model for other institutions.",
        "Women Empowerment": "Our Women Empowerment project focuses on building confidence, independence, and vocational skills. Through faculty-guided mentorship, we provide self-defense training, vocational skill development, and mental well-being sessions to empower women in and around the campus.",
        "RE:NIT": "RE:NIT focuses on a circular economy model by recycling campus waste into usable components and artistic installations. This project reduces landfill waste and promotes creative recycling solutions.",
        "PAYJAL": "PAYJAL is our dedicated water initiative. We are installing rainwater harvesting systems to ensure a steady supply of clean drinking water across all campus hostels, reducing reliance on external water sources.",
        "Cooling Systems": "This energy initiative develops passive cooling mechanisms for academic blocks. By utilizing energy-efficient designs, we aim to significantly reduce the campus's carbon footprint and electricity consumption.",
        "Green Campus": "The Green Campus sub-project involves massive plantation drives. Our goal is to enhance air purity and local biodiversity, creating a lush, green environment on and around the NIT Kurukshetra campus.",
        "Sustainable Dining": "Sustainable Dining targets food waste in campus messes. Using data-driven analysis, we optimize food consumption and introduce biodegradable materials to eliminate waste and promote eco-friendly dining.",
        "Waste Management Campaign": "<p>The Waste Management Campaign is an important community-based project aimed at creating awareness about proper waste disposal, segregation, recycling, and environmental cleanliness. With the rapid growth of population and urbanization, waste generation has increased significantly in both rural and urban areas. Improper disposal of waste leads to pollution, health hazards, blockage of drainage systems, and environmental degradation. Therefore, this project focuses on educating people about responsible waste management practices and encouraging sustainable habits.</p><p>The main objective of the campaign is to teach people how to separate waste into categories such as biodegradable waste, recyclable waste, and hazardous waste. Biodegradable waste includes food scraps, vegetable peels, and garden waste, which can be converted into compost. Recyclable waste includes paper, plastic, metal, and glass, which can be reused after processing. Hazardous waste includes batteries, medical waste, chemicals, and electronic waste that require special handling. By segregating waste at the source, the burden on landfills can be reduced and recycling becomes easier.</p><p>The project can be implemented through awareness drives, street plays, poster-making competitions, rallies, workshops, and door-to-door campaigns. NSS volunteers can visit schools, markets, households, and public places to spread awareness about cleanliness and waste segregation. They can distribute pamphlets explaining the importance of reducing plastic use and adopting reusable alternatives such as cloth bags and steel bottles.</p><p>Another important activity under this project is organizing community clean-up drives in streets, parks, bus stops, ponds, and marketplaces. Volunteers can collect litter, clean surroundings, and motivate residents to maintain cleanliness regularly. Dustbins labeled for wet waste and dry waste can be installed in public areas. Compost pits may also be created in villages or campuses to convert organic waste into manure for gardening.</p><p>The project also promotes the concept of \"Reduce, Reuse, Recycle.\" People are encouraged to reduce unnecessary consumption, reuse materials whenever possible, and recycle waste items responsibly. For example, old clothes can be donated, newspapers can be sold for recycling, and plastic bottles can be reused for gardening purposes.</p><p>The expected outcomes of the Waste Management Campaign include cleaner surroundings, reduced pollution, improved public health, and increased environmental responsibility among citizens. It also develops leadership, teamwork, and social responsibility among student volunteers. This project can create long-term behavioral changes in society and support national cleanliness missions such as Swachh Bharat Abhiyan.</p>",
        "Event Management for Community Development": "<p>Event Management for Community Development is a project designed to organize social welfare events such as health camps, blood donation drives, educational seminars, skill development workshops, and awareness programs for the benefit of society. It also helps students learn planning, coordination, budgeting, leadership, and communication skills through real-life event execution.</p><p>The main aim of this project is to serve the community by conducting useful programs that address local needs. Many rural and urban communities lack awareness or access to services related to health, education, career guidance, and skill development. By organizing well-planned events, these needs can be fulfilled while simultaneously giving students valuable management experience.</p><p>The project begins with identifying community needs through surveys or discussions with local residents. Based on the findings, suitable events can be planned. For example, if people require health support, a free medical camp can be organized with doctors and nurses. If youth need employment opportunities, skill training workshops on computer literacy, resume writing, or entrepreneurship can be arranged.</p><p>Students participating in this project learn various stages of event management. These include goal setting, preparing schedules, budgeting, arranging venue and logistics, contacting resource persons, promoting the event, managing registrations, coordinating volunteers, and ensuring smooth execution on the day of the event. They also learn how to solve unexpected problems such as crowd control, technical issues, or delays.</p><p>Examples of events under this project include blood donation camps, eye-checkup camps, cleanliness drives, legal awareness sessions, career counseling seminars, women empowerment workshops, environmental campaigns, and sports tournaments. Cultural programs may also be organized to bring communities together and celebrate unity.</p><p>The project develops leadership and teamwork among volunteers. Students learn to work under pressure, communicate with different stakeholders, and take responsibility for outcomes. These practical skills are highly valuable in future careers, especially in management, administration, and entrepreneurship. The community benefits through access to useful services, expert guidance, and awareness on important issues. For instance, a blood donation camp can save lives, while a digital literacy workshop can help senior citizens use online services. Skill development programs can improve employability of local youth.</p>",
        "Digital Literacy Drive": "<p>The Digital Literacy Drive is a project aimed at teaching basic computer and smartphone skills to community members, especially senior citizens, rural populations, women, and economically weaker sections. In today's digital era, many essential services such as banking, education, healthcare, ticket booking, and communication have shifted online. However, a large section of society still lacks the skills needed to use these services. This project helps bridge the digital divide and promotes digital inclusion.</p><p>The main objective of the Digital Literacy Drive is to empower people with practical knowledge of digital tools. Participants are taught how to use smartphones, computers, internet browsers, email, mobile apps, and online platforms safely and confidently. They are also introduced to services such as UPI payments, online banking, railway ticket booking, telemedicine, and digital learning resources. The project can begin with identifying target groups who need assistance. NSS volunteers can conduct surveys in villages, slum areas, or residential colonies to identify senior citizens, homemakers, workers, or students who need digital training. Training sessions can then be organized in schools, community halls, panchayat buildings, or campuses.</p><p>Teaching methods should be simple, practical, and hands-on. Volunteers can explain basic smartphone settings, making phone calls, sending messages, using WhatsApp, taking photos, scanning QR codes, and browsing websites. They can also help people create email accounts and teach how to send and receive emails. Online safety topics such as avoiding OTP scams, fake links, cyber fraud, and protecting passwords are equally important.</p><p>Special attention can be given to senior citizens, who often find technology challenging. Patient one-to-one guidance can help them learn digital payments, online appointment booking, or video calling family members. Women in self-help groups can be trained to use e-commerce platforms or digital payment systems for small businesses. This project offers many social benefits. It saves people time, increases access to services, improves financial inclusion, and boosts confidence. Farmers can access weather updates and market prices online. Students can attend online classes and use educational apps. Job seekers can apply for opportunities online.</p><p>For student volunteers, the project develops communication skills, patience, teaching ability, and social awareness. It also gives them satisfaction by helping others become digitally independent.</p>",
        "Disaster Management Preparedness": "<p>Disaster Management Preparedness is an important social service project that focuses on educating communities about safety measures, emergency response, and preparedness during natural or man-made disasters. India frequently faces disasters such as floods, earthquakes, cyclones, landslides, fires, droughts, and accidents. Many lives and properties are lost because people are unaware of preventive actions and emergency procedures. This project aims to build awareness, preparedness, and resilience among the public so that communities can respond quickly and effectively during emergencies.</p><p>The primary objective of this project is to train people on what to do before, during, and after a disaster. Preparedness reduces panic, confusion, and damage. The project can target schools, colleges, villages, urban residential areas, and local communities where disaster awareness is limited. NSS volunteers can work with local authorities, hospitals, fire departments, police, and disaster response teams to conduct awareness sessions and demonstrations.</p><p>The project may begin with identifying common disaster risks in the local area. For example, flood-prone areas need training on evacuation and safe shelter, while earthquake-prone areas need awareness about safe building exits and drop-cover-hold techniques. Fire-prone areas need training in using fire extinguishers and emergency exits. By understanding local risks, suitable training programs can be organized. One major activity under this project is conducting mock drills. These drills simulate real emergency situations and teach people how to evacuate safely, assist injured persons, and contact emergency services. Mock drills in schools, offices, and residential areas help people practice disciplined movement during emergencies. Students learn how to remain calm and follow instructions. Another important component is first-aid training. Volunteers can invite doctors or certified trainers to teach CPR, wound dressing, fracture support, and handling unconscious victims. Immediate first aid can save lives before medical help arrives. Awareness can also be created about emergency kits containing water, medicines, flashlight, batteries, documents, and food supplies.</p><p>The project also emphasizes communication during disasters. Communities should know emergency contact numbers, nearest shelters, hospital locations, and relief centers. Volunteers can distribute pamphlets, posters, and booklets in local languages. Social media and mobile alerts may also be used for awareness. The benefits of this project are significant. Communities become more alert, organized, and confident in handling emergencies. Loss of life and injury can be reduced. Students gain leadership, discipline, teamwork, and crisis management skills. They also develop a sense of responsibility toward society. This project supports national disaster management goals and contributes to building safer communities. Schools and colleges can make it an annual activity so that preparedness remains active and updated.</p>",
        "Green Campus Initiative": "<p>The Green Campus Initiative is an environmental project aimed at making schools, colleges, and public institutions eco-friendly, clean, energy-efficient, and sustainable. With rising pollution, climate change, water scarcity, and waste generation, it has become necessary to adopt environmentally responsible practices in educational institutions. Since campuses have large numbers of students and staff, they are ideal places to promote green habits and create awareness among future generations.</p><p>The main objective of this project is to transform the campus into a model of sustainability through tree plantation, waste management, rainwater harvesting, energy conservation, plastic reduction, and eco-friendly practices. It also seeks to develop environmental responsibility among students and staff members.</p><p>One major activity under this project is tree plantation. Volunteers can plant shade trees, fruit trees, medicinal plants, and flowering plants across the campus. Trees improve air quality, reduce heat, beautify surroundings, and support biodiversity. Students can adopt trees and take responsibility for watering and maintenance. Waste management is another key component. Separate dustbins for wet waste and dry waste can be installed across the campus. Compost pits can convert biodegradable waste such as leaves and food waste into manure for gardens. Recycling campaigns can be conducted for paper, plastic, and e-waste. Students can be encouraged to reduce single-use plastics by using reusable bottles and bags.</p><p>Water conservation measures such as rainwater harvesting can be implemented. Rainwater collected from rooftops can be stored or used for gardening and sanitation purposes. Awareness programs can teach students how to avoid water wastage in hostels, canteens, and washrooms.</p><p>Energy conservation is equally important. The campus can promote LED lighting, solar panels, energy-efficient appliances, and switching off unused fans and lights. Awareness stickers and campaigns can remind people to save electricity. Green audits may also be conducted to measure resource consumption and suggest improvements. The initiative can include bicycle use, walk-to-campus days, herbal gardens, paperless administration, eco-clubs, and environmental competitions such as poster making, debates, and quiz contests. These activities make sustainability engaging and practical.</p><p>The benefits of a Green Campus Initiative are wide-ranging. It reduces pollution, lowers electricity and water costs, improves campus beauty, and creates a healthier learning environment. It also instills lifelong eco-friendly habits in students. Volunteers develop teamwork, leadership, planning ability, and environmental awareness. This project aligns with national and global sustainability goals and can inspire surrounding communities to adopt similar practices. Educational institutions can become centers of environmental leadership.</p>",
        "Community Health": "<p>Community Health Awareness is an important social project aimed at educating people about hygiene, nutrition, disease prevention, and healthy living practices. In many rural and urban low-income areas, people suffer from health problems due to lack of awareness, poor sanitation, unhealthy food habits, and delayed medical treatment. Many diseases can be prevented through simple habits such as handwashing, balanced diet, vaccination, and regular health check-ups. This project focuses on spreading practical health knowledge among communities and improving overall public well-being.</p><p>The primary objective of this project is to create awareness regarding preventive healthcare. Instead of treating diseases after they occur, preventive care helps reduce illness before it begins. NSS volunteers can organize seminars, health camps, street plays, poster exhibitions, and door-to-door awareness campaigns in villages, slums, schools, and residential colonies. Doctors, nurses, dieticians, and health workers may be invited to provide expert guidance.</p><p>One key area of focus is personal hygiene. People are educated about handwashing with soap, safe drinking water, clean toilets, waste disposal, oral hygiene, and maintaining a clean environment. Poor hygiene often leads to infections such as diarrhea, skin diseases, and respiratory problems. Teaching children and families proper hygiene habits can greatly reduce illness. Nutrition awareness is another major component. Many families lack knowledge about balanced diets and proper nutrition. Volunteers can explain the importance of proteins, vitamins, fruits, vegetables, milk, and iron-rich foods. Awareness regarding malnutrition, anemia, obesity, and junk food consumption can also be created. Low-cost nutritious meal plans suitable for local communities may be suggested.</p><p>Special campaigns can focus on women's health, child care, vaccination, and menstrual hygiene. Adolescent girls can be educated about menstrual cleanliness, use of sanitary products, and nutrition. Pregnant women can be informed about prenatal care and regular medical check-ups. Parents can be guided about child immunization schedules. The project may also include free health screening camps for blood pressure, diabetes, eye check-up, dental care, and BMI measurement. Early detection of health problems helps in timely treatment. Awareness regarding mental health, stress management, yoga, and exercise can also be included.</p><p>The benefits of this project are significant. Communities become healthier, disease burden reduces, sanitation improves, and healthcare awareness increases. Students gain communication skills, empathy, leadership qualities, and a sense of service. This initiative supports public health missions and contributes to a healthier society. Regular follow-up programs can make the impact long-lasting.</p>",
        "Literacy Campaigns": "<p>Literacy Campaigns are social development projects focused on promoting reading, writing, and basic education among illiterate adults and underprivileged children. Education is one of the most powerful tools for personal growth, employment, and social empowerment. However, many people in rural and economically weaker sections remain deprived of basic literacy due to poverty, lack of access, or social barriers. This project aims to reduce illiteracy and create equal learning opportunities for all.</p><p>The main objective of literacy campaigns is to teach people how to read, write, count, and perform everyday educational tasks. NSS volunteers can organize evening classes, weekend teaching centers, mobile learning camps, and educational workshops in villages, slum areas, orphanages, and labor colonies. Adults who missed formal schooling and children who need academic support can greatly benefit. Adult literacy is an important part of the project. Many adults face difficulties in reading signs, filling forms, using bank services, or helping their children in studies. Volunteers can teach alphabets, numbers, signatures, simple sentences, and basic arithmetic in local languages. Practical lessons such as reading medicine labels, bus boards, or bank slips make learning more useful. Children from underprivileged families often lack study materials or guidance. Volunteers can distribute free books, notebooks, pencils, school bags, and storybooks. Tuition support classes can help students improve school performance. Reading clubs and storytelling sessions can make learning enjoyable.</p><p>The campaign may also focus on digital literacy along with traditional literacy. Learners can be introduced to basic smartphone usage, reading messages, and using educational apps. This is especially useful in modern times where many services are digital. Awareness sessions can be conducted for parents to emphasize the importance of sending children to school regularly, especially girls. Many children drop out due to financial pressure or social reasons. Volunteers can motivate families to prioritize education as an investment for the future.</p><p>The benefits of literacy campaigns are far-reaching. Literate individuals gain confidence, independence, better employment opportunities, and stronger participation in society. Children receiving support are more likely to continue education and succeed academically. For volunteers, the project develops patience, teaching ability, communication skills, and social responsibility. It also provides emotional satisfaction by transforming lives through education. This project supports national literacy goals and inclusive development. Continuous efforts and follow-up are necessary for long-term success.</p>",
        "Elder Care": "<p>Elder Care Initiatives are compassionate social service projects aimed at supporting senior citizens, especially those living alone or in old age homes. Many elderly people face loneliness, health issues, mobility problems, emotional stress, and lack of regular social interaction. After retirement or family separation, some feel neglected and isolated. This project seeks to provide care, companionship, medical assistance, and respect to elderly members of society.</p><p>The main objective of the project is to improve the physical and emotional well-being of senior citizens. NSS volunteers can regularly visit old age homes, hospitals, and neighborhoods where elderly people need support. They can spend time talking, listening, and engaging with them in meaningful activities. Loneliness is a major issue among older adults. Volunteers can organize recreational sessions such as music, storytelling, reading newspapers, indoor games, yoga, and cultural programs. These activities create happiness and mental stimulation. Celebrating birthdays and festivals with senior citizens also brings joy and a sense of belonging. Health support is another important component. Free medical camps can be arranged for blood pressure, sugar testing, eye check-ups, dental care, and general consultation. Volunteers may help elderly people in maintaining medicine schedules, hospital visits, or filling medical forms.</p><p>Awareness sessions can be conducted on topics such as healthy aging, exercise, balanced diet, stress management, and digital literacy. Teaching elderly persons how to make video calls or use smartphones helps them stay connected with family members. The project can also assist senior citizens in accessing pension schemes, healthcare benefits, Aadhaar services, or banking support. Many older adults struggle with paperwork or online procedures. The benefits of this initiative are emotional as well as practical. Elderly people feel valued, respected, and less isolated. Their confidence and happiness improve. Students learn empathy, patience, gratitude, and responsibility toward elders. The project also strengthens intergenerational bonding. Young people gain wisdom from seniors' life experiences, while seniors feel energized by youthful interaction. This initiative promotes the cultural value of respecting elders and supports social harmony.</p>",
        "Women Empowerment Workshops": "<p>Women Empowerment Workshops are important social development projects aimed at improving the confidence, independence, skills, and social status of women in society. Although women play a vital role in family, education, economy, and nation-building, many still face challenges such as lack of education, unemployment, financial dependency, discrimination, domestic violence, and limited access to opportunities. This project seeks to empower women by providing knowledge, practical skills, legal awareness, and self-confidence so that they can lead independent and dignified lives.</p><p>The main objective of this project is to create opportunities for women through education and skill development. NSS volunteers can organize workshops in villages, urban communities, colleges, and self-help groups. These workshops may cover vocational training, entrepreneurship, digital literacy, health awareness, financial management, leadership, and legal rights.</p><p>Skill development is one of the most effective tools for empowerment. Women can be trained in tailoring, handicrafts, food processing, beauty services, computer basics, online marketing, and home-based business ideas. These skills help women generate income and become financially independent. Workshops may also include training on how to start small businesses, prepare products, manage customers, and use digital payments. Legal awareness is another key component. Many women are unaware of their rights and available protections under law. Sessions can be conducted on domestic violence laws, workplace harassment prevention, inheritance rights, marriage laws, and government welfare schemes. Women should know where to seek help in difficult situations. Self-defense training can also be included. Basic self-defense techniques improve confidence and personal safety. Awareness regarding cyber safety, online harassment, and emergency helplines is equally relevant in modern times.</p><p>Health and wellness programs are essential. Workshops can address nutrition, reproductive health, menstrual hygiene, mental health, stress management, and regular medical check-ups. Healthy women contribute to healthy families and communities. The project can encourage leadership by motivating women to participate in local governance, school committees, entrepreneurship groups, and community decision-making. Successful women entrepreneurs, officers, or professionals can be invited as speakers to inspire participants.</p><p>The benefits of women empowerment workshops are far-reaching. Women gain confidence, knowledge, skills, and economic opportunities. Families benefit through improved income, education, and health. Communities become more progressive and gender-sensitive. For volunteers, the project develops communication skills, organizational ability, empathy, and awareness of social issues. It also gives satisfaction through meaningful community impact. This initiative supports national goals of gender equality and inclusive growth. Empowered women become agents of change in society.</p>",
        "Anti-Substance Abuse": "<p>Anti-Substance Abuse Awareness is a social welfare project focused on educating people, especially youth, about the harmful effects of drugs, alcohol, tobacco, and other addictive substances. Substance abuse has become a serious social and health problem in many communities. It affects physical health, mental stability, family relationships, education, employment, and public safety. Many young people begin using harmful substances due to peer pressure, curiosity, stress, or lack of awareness. This project aims to prevent addiction through education, counseling, and community support.</p><p>The main objective of this project is to spread awareness about the dangers of substance abuse and encourage healthy lifestyle choices. NSS volunteers can organize campaigns in schools, colleges, villages, and urban neighborhoods. Activities may include seminars, street plays, poster competitions, rallies, documentaries, and expert talks by doctors, psychologists, or recovered individuals. One key area of awareness is explaining the health risks of addiction. Tobacco use can lead to cancer and lung disease. Alcohol abuse can damage the liver, brain, and relationships. Drug abuse can cause severe mental and physical dependency. Youth should understand that temporary pleasure can lead to long-term suffering.</p><p>The project also highlights the social consequences of addiction. Substance abuse often leads to family conflict, violence, accidents, crime, financial loss, and poor academic or job performance. Many talented individuals lose opportunities because of addiction. Mental health support is another important aspect. Some people turn to substances due to stress, depression, loneliness, or emotional trauma. Therefore, awareness programs should also promote counseling, emotional support, exercise, meditation, and healthy coping methods. Students can be encouraged to seek help rather than hide problems. Peer pressure resistance training can be useful for teenagers and college students. Role-play activities may teach them how to say no confidently and choose better company. Sports, arts, and cultural activities can be promoted as positive alternatives. The project can also provide information about rehabilitation centers, helplines, counseling services, and medical treatment for those already struggling with addiction. Recovery should be treated with compassion, not stigma.</p><p>The benefits of this initiative are substantial. Youth become more informed and cautious. Families become stronger, crime may reduce, and communities become healthier. Students volunteering in the project gain leadership, communication skills, and social sensitivity. This campaign supports public health and national anti-drug missions. Repeated awareness efforts are important because prevention works best through continuous education.</p>",
        "Financial Literacy Program": "<p>The Financial Literacy Program is a social development project designed to educate people about money management, savings, budgeting, banking services, digital payments, investments, and financial security. Many individuals, especially in rural and economically weaker communities, lack awareness of basic financial concepts. As a result, they may fall into debt, become victims of fraud, or fail to plan for emergencies and future needs. This project aims to empower people with practical financial knowledge so they can make informed and responsible decisions.</p><p>The main objective of the project is to teach people how to manage their income wisely. NSS volunteers can organize awareness sessions in villages, schools, colleges, self-help groups, and residential communities. Topics may include preparing household budgets, controlling unnecessary expenses, saving regularly, using banks, and understanding financial goals.</p><p>Budgeting is one of the most useful skills taught under this program. Families learn how to track income and expenses, prioritize needs over wants, and avoid overspending. Even small savings made consistently can create emergency funds and future security. People are encouraged to save money in bank accounts rather than keeping cash at home.</p><p>The project also promotes banking awareness. Many people are unfamiliar with services such as savings accounts, recurring deposits, fixed deposits, ATM usage, and mobile banking. Volunteers can explain how to open bank accounts, use passbooks, withdraw money safely, and access government benefit transfers. Digital payment education is highly relevant today. Participants can be trained to use UPI apps, QR code payments, online transfers, and secure digital transactions. Awareness about fraud prevention, OTP scams, fake calls, and cyber safety is equally important.</p><p>Basic investment awareness may also be introduced. People can be informed about low-risk options such as fixed deposits, post office savings schemes, public provident fund, and insurance plans. The concept of long-term planning for children's education, retirement, or medical emergencies can be discussed. Special focus can be given to women, farmers, laborers, and youth. Women who manage household expenses benefit greatly from budgeting knowledge. Farmers can learn crop insurance and loan planning. Youth can learn about responsible spending and early savings habits.</p><p>The benefits of the Financial Literacy Program are extensive. People become financially disciplined, confident, and less vulnerable to exploitation. Families gain stability and are better prepared for emergencies. Students volunteering in the project develop communication skills, leadership, and social awareness. This initiative supports financial inclusion and national development goals by encouraging formal banking and smart money habits.</p>",
        "Self-Help Groups (SHGs)": "<p>Self-Help Groups (SHGs) are community-based groups formed mainly by women, farmers, or economically weaker individuals who come together to save money regularly, support each other financially, and undertake income-generating activities. This project aims to encourage the formation and strengthening of SHGs so that members can become financially independent, socially confident, and economically productive.</p><p>The main objective of the project is to promote collective savings and self-reliance. Members of an SHG usually contribute a small fixed amount regularly into a common fund. This fund can be used to provide small loans to members during emergencies or for business purposes. Over time, SHGs may also receive support from banks, NGOs, or government schemes.</p><p>NSS volunteers can help communities understand the benefits of SHGs and assist in forming new groups. They can guide members in selecting leaders, maintaining records, conducting meetings, and managing finances transparently. Training can be provided on bookkeeping, bank account opening, and savings discipline.</p><p>One of the biggest advantages of SHGs is access to small loans without depending on moneylenders who charge high interest. Members can borrow for medical needs, children's education, agriculture, or starting small businesses. Repayment within the group builds trust and discipline.</p><p>SHGs can also become centers of entrepreneurship. Women may start activities such as tailoring, food processing, dairy farming, handicrafts, candle making, pickle production, or catering services. Farmers can cooperate in seed purchase, storage, or market access. Group-based enterprises reduce risk and improve bargaining power. The project can include training in digital payments, product packaging, branding, online marketing, and participation in local exhibitions.</p><p>Volunteers may connect SHGs with government welfare schemes, skill programs, or bank loans. Beyond financial benefits, SHGs also create social empowerment. Members gain confidence, leadership qualities, and decision-making ability. Women who were earlier financially dependent often become active contributors to family income. Group meetings also provide emotional support and awareness about health, education, and rights. The benefits of SHGs are long-lasting. Families experience improved income, reduced debt dependency, and stronger financial security. Communities become more cooperative and economically active. Students working on this project learn grassroots development, teamwork, and social responsibility. This initiative strongly supports rural development and women empowerment missions across India.</p>",
        "Micro-Financing Awareness": "<p>Micro-Financing Awareness is a project aimed at educating low-income communities about small loan opportunities, credit support systems, and responsible borrowing for income generation. Many poor families and small entrepreneurs need small amounts of capital to start businesses, buy tools, improve farming, or manage emergencies. However, due to lack of awareness or inability to access formal banks, they often depend on private lenders who charge high interest. This project helps people understand safe and beneficial micro-finance options.</p><p>The main objective of the project is to inform communities about micro-loans offered by banks, micro-finance institutions, self-help groups, and government-supported schemes. NSS volunteers can conduct awareness camps in villages, slums, and low-income neighborhoods where financial access is limited.</p><p>Participants can be educated about how micro-financing works. Small loans are provided for productive purposes such as buying sewing machines, livestock, seeds, shop materials, carts, tools, or raw materials for cottage industries. These loans are usually easier to access than traditional business loans and may require group guarantees rather than large collateral. The project should also teach responsible borrowing. People must understand that loans should be taken for productive or urgent needs, not unnecessary consumption. Borrowers should calculate repayment capacity, maintain discipline, and avoid multiple loans that create debt burdens.</p><p>Special awareness can be created for women entrepreneurs, youth, street vendors, and farmers. Women can start home-based businesses. Youth can launch repair services or small shops. Farmers may use loans for irrigation equipment, seeds, or storage. Volunteers can help people compare loan options, interest rates, repayment schedules, and government subsidies. Assistance may also be given in filling forms, collecting documents, and connecting with banks or micro-finance agencies. The project may include success stories of local entrepreneurs who improved their lives through small loans. Such examples motivate others and build confidence.</p><p>The benefits of micro-financing awareness are significant. Families gain income opportunities, reduce dependence on moneylenders, and become economically stronger. Local entrepreneurship increases, creating jobs and community growth. Students participating in this project gain understanding of rural economy, financial systems, and development challenges. They also improve communication and problem-solving skills. This initiative supports inclusive finance and poverty reduction goals.</p>",
        "Start-Up Mentorship": "<p>Start-Up Mentorship is a financial and entrepreneurship-oriented project aimed at supporting aspiring entrepreneurs, students, artisans, and small business owners in developing sustainable business ideas and successful enterprises. Many talented individuals have innovative ideas or useful skills but lack guidance in planning, finance, marketing, legal formalities, and business management. This project seeks to bridge that gap by providing mentorship, training, and practical support to help new ventures grow confidently.</p><p>The main objective of this project is to guide individuals in converting ideas into viable businesses. NSS volunteers, faculty members, professionals, and industry experts can collaborate to organize mentorship camps, workshops, and one-to-one advisory sessions. These programs can target college students, unemployed youth, women entrepreneurs, artisans, farmers, and local shop owners. The project may begin with idea identification. Participants can be encouraged to observe local problems and create solutions through products or services. For example, eco-friendly packaging, homemade food brands, tuition services, handicrafts, repair centers, agri-products, or digital services can become promising start-ups. Mentors can help evaluate whether the idea solves a real need and has market demand.</p><p>Business planning is another key component. Participants can be taught how to define target customers, estimate costs, set pricing, identify competitors, and calculate profits. They may learn to prepare simple business plans, sales strategies, and growth goals. Understanding these basics helps reduce risk. Financial guidance is highly important. Many start-ups fail due to poor cash management. Mentors can explain budgeting, working capital, bank loans, government schemes, grants, crowdfunding, and investor pitching. Participants can also learn bookkeeping and tax basics. Marketing support can significantly improve success. Workshops may cover branding, logo creation, customer service, social media marketing, WhatsApp business tools, online selling platforms, and local promotion methods. Small businesses can reach wider markets through digital tools. The project can also include legal and operational guidance such as business registration, GST basics, licenses, packaging rules, and quality standards. This is especially useful for food businesses and retail ventures.</p><p>Local artisans and traditional workers can benefit by learning better packaging, online sales, and modern customer engagement. Farmers may be guided toward value-added products like pickles, honey, or processed foods. The benefits of Start-Up Mentorship are extensive. Participants gain confidence, knowledge, income opportunities, and independence. New businesses generate employment and strengthen the local economy. Students volunteering in the project gain leadership, networking, business understanding, and social impact experience. This initiative supports innovation, self-employment, and economic development. It aligns with national missions promoting entrepreneurship and start-up culture.</p>",
        "Savings and Insurance Education": "<p>Savings and Insurance Education is a financial awareness project focused on teaching individuals and families the importance of saving money regularly and protecting themselves through suitable insurance plans. Many people earn income but do not save systematically or prepare for emergencies. Unexpected events such as illness, accidents, crop loss, death of an earning member, or natural disasters can create severe financial hardship. This project aims to build financial security through disciplined savings habits and awareness of insurance protection.</p><p>The main objective of this project is to help people understand that financial planning is essential for a stable future. NSS volunteers can organize awareness camps in villages, schools, colleges, self-help groups, and residential areas. Sessions may explain emergency funds, long-term savings, insurance benefits, and risk management in simple language. Savings education is one of the key components. Families can be encouraged to save a small portion of income regularly, even if earnings are limited. People may be taught to differentiate between needs and unnecessary expenses. Methods such as savings accounts, recurring deposits, fixed deposits, post office schemes, and pension plans can be introduced.</p><p>Emergency funds are especially important. Participants can be advised to build a reserve for medical treatment, school fees, sudden unemployment, or urgent travel. Even small regular deposits can create useful protection over time. Insurance awareness is another major part of the project. Many people avoid insurance because they do not understand it or believe it is unnecessary. Volunteers can explain that insurance provides financial support during difficult situations. Topics may include life insurance, health insurance, vehicle insurance, crop insurance, and accident coverage.</p><p>Special attention can be given to farmers, laborers, women, and low-income households. Farmers may benefit from crop insurance against weather loss. Daily wage earners may need health or accident insurance. Families with children can plan education savings. The project should also teach participants how to compare policies, read terms carefully, avoid fake agents, and choose affordable and suitable plans. Awareness about government-backed schemes such as low-cost insurance and pension plans can be included.</p><p>The benefits of this initiative are substantial. Families become financially disciplined, less vulnerable to shocks, and more future-ready. Insurance reduces the burden of sudden crises. Students volunteering in the project gain communication skills, social awareness, and understanding of financial systems. This project supports inclusive financial growth and household resilience.</p>",
        "Skill-Based Entrepreneurship Training": "<p>Skill-Based Entrepreneurship Training is a project designed to help youth, women, and unemployed individuals develop practical skills that can be converted into income-generating businesses. Many people possess talent but lack professional training or confidence to start earning independently. This project focuses on teaching useful vocational and technical skills while encouraging self-employment and entrepreneurship.</p><p>The main objective is to make participants job creators instead of job seekers. Training can be provided in tailoring, handicrafts, bakery products, food processing, mobile repair, beauty services, computer work, graphic design, digital marketing, and similar fields. After learning these skills, participants can begin home-based or small-scale enterprises with limited investment.</p><p>Workshops may include product quality improvement, customer handling, pricing, packaging, and marketing. Participants can also learn how to use social media and online platforms to sell products. This helps them reach wider markets and earn better profits. The project especially benefits women who wish to earn from home, rural youth seeking employment, and students interested in freelancing or side businesses. Volunteers and trainers can guide them in preparing business plans and accessing government support schemes.</p><p>The benefits include improved employability, increased family income, confidence, and economic independence. Communities benefit when more people become productive and self-reliant.</p>",
        "Start-Up Incubation Support": "<p>Start-Up Incubation Support is a project that provides guidance, mentorship, and resources to aspiring entrepreneurs who have innovative ideas but need help turning them into real businesses. Many young people have creative solutions for local problems but lack support in planning, finance, technology, and market access.</p><p>The main objective is to nurture early-stage business ideas. Participants can present concepts related to technology, agriculture, food products, education services, health solutions, or local business innovations. Mentors can help evaluate feasibility, customer demand, and long-term sustainability. The project can include idea competitions, business model workshops, prototype demonstrations, and investor pitch sessions. Guidance on funding sources, registration, branding, and scaling strategies may also be provided.</p><p>Students and youth gain exposure to entrepreneurship culture and innovation thinking. They learn how to solve problems commercially and responsibly. Communities benefit when successful start-ups generate jobs and useful products. This initiative supports economic growth and encourages a culture of creativity and enterprise.</p>",
        "E-Marketplace Development": "<p>E-Marketplace Development is a project aimed at helping local artisans, small traders, farmers, and women entrepreneurs sell their products through digital platforms. Many talented producers create quality goods but have limited market access. By using e-commerce tools, they can reach customers beyond their local area. The main objective is to promote digital selling and increase income opportunities. Participants can be trained to list products on online marketplaces, use WhatsApp Business, create social media pages, and manage online payments.</p><p>Products such as handicrafts, homemade foods, clothing, decorations, agricultural products, and customized items can be sold online. Volunteers may assist in taking product photos, writing descriptions, packaging, and customer communication. The project also teaches inventory management, pricing, delivery coordination, and customer feedback handling. This improves professionalism and trust.</p><p>The benefits include larger markets, better earnings, business growth, and digital empowerment. Rural producers and women entrepreneurs especially gain from direct customer access.</p>",
        "Agripreneurship Initiatives": "<p>Agripreneurship Initiatives are projects that encourage farmers and rural youth to treat agriculture as a business opportunity rather than only traditional farming. Agriculture offers many possibilities such as organic farming, mushroom cultivation, dairy, beekeeping, hydroponics, food processing, seed production, and agri-tourism.</p><p>The main objective is to increase rural income through innovation and value addition. Farmers can be trained in modern techniques, packaging, branding, and direct marketing. Instead of selling raw produce only, they can sell processed goods like pickles, juices, flour, honey, or dried fruits. The project can also introduce smart farming tools such as drip irrigation, mobile advisory apps, soil testing, and greenhouse methods. Youth can be encouraged to launch agri-service businesses like equipment rental, drone spraying, or farm consultancy.</p><p>Benefits include better profits, reduced migration, modernized farming, and rural employment generation. Students volunteering in this project gain understanding of agriculture and sustainability.</p>",
        "Entrepreneurial Awareness Camps": "<p>Entrepreneurial Awareness Camps are motivational programs designed to introduce people, especially youth and students, to the concept of entrepreneurship. Many individuals depend only on job opportunities and do not realize they can create businesses through ideas, skills, and determination.</p><p>The main objective is to build entrepreneurial mindset and confidence. Camps may include talks by successful entrepreneurs, business case studies, idea-generation sessions, and information on funding schemes. Participants learn about risk-taking, innovation, customer needs, teamwork, marketing, and leadership. They also receive guidance on government start-up programs, MSME registration, and loan facilities. Such camps inspire participants to identify local business opportunities such as tuition centers, online services, food ventures, repair work, agriculture businesses, or digital freelancing.</p><p>The benefits include self-confidence, creativity, and employment generation mindset. Communities benefit when more individuals choose productive entrepreneurship paths.</p>",
        "Recycling and Upcycling Businesses": "<p>Recycling and Upcycling Businesses are projects that promote entrepreneurship while solving environmental problems. Waste materials such as plastic bottles, old clothes, paper, wood, metal scraps, and tires can be converted into useful or decorative products.</p><p>The main objective is to generate income from waste while reducing pollution. Participants can be trained to create bags from old fabric, furniture from wooden waste, décor items from bottles, paper products from scrap, or compost from organic waste. The project teaches creativity, design thinking, product finishing, and sustainable business models. Items produced can be sold in local markets, exhibitions, schools, and online platforms. This initiative is especially suitable for women groups, students, and low-investment entrepreneurs. It encourages eco-friendly thinking and circular economy practices.</p><p>Benefits include cleaner surroundings, reduced waste, low-cost entrepreneurship, and environmental awareness.</p>",
        "Community-Based Food Services": "<p>Community-Based Food Services are projects that establish small food businesses run by women groups, self-help groups, or youth teams. Food services such as tiffin centers, snack stalls, catering, healthy lunch services, and festival food counters can provide steady income.</p><p>The main objective is to create livelihood opportunities using cooking skills and local demand. Participants can be trained in hygiene, menu planning, costing, packaging, customer service, and digital payments. Women's groups can run canteens near schools or offices. Youth can provide event catering or home-delivery meals. Nutritious local food can also be promoted instead of unhealthy fast food.</p><p>The project teaches teamwork, time management, procurement, budgeting, and quality control. With proper branding and consistency, such services can grow into sustainable businesses. Benefits include employment generation, women empowerment, local food promotion, and affordable meal options for the community.</p>"
    };

    const projectCards = document.querySelectorAll('.modern-sub-card, .flagship-wrapper-v2');
    let projectModal;
    
    if (document.getElementById('projectDetailsModal')) {
        projectModal = new bootstrap.Modal(document.getElementById('projectDetailsModal'));
    }
    
    projectCards.forEach(card => {
        card.style.cursor = 'pointer';
        card.classList.add('project-clickable');
        
        card.addEventListener('click', function() {
            let titleEl = card.querySelector('h5, h2');
            let rawTitle = titleEl ? titleEl.innerText : 'Project Details';
            // Clean up emojis like 🌍 and 🌸 from flagship titles
            let title = rawTitle.replace(/[\u{1F300}-\u{1F5FF}\u{1F900}-\u{1F9FF}\u{1F600}-\u{1F64F}\u{1F680}-\u{1F6FF}\u{2600}-\u{26FF}\u{2700}-\u{27BF}]/gu, '').trim();
            
            let iconEl = card.querySelector('.sub-icon-box i');
            let iconHtml = iconEl ? iconEl.outerHTML : '<i class="bi bi-star-fill"></i>';
            
            let tagEl = card.querySelector('.card-tag, .status-badge');
            let tag = tagEl ? tagEl.innerText : 'Initiative';
            
            let fallbackTextEl = card.querySelector('p');
            let fallbackText = fallbackTextEl ? fallbackTextEl.innerText : 'Details are being updated. Check back soon.';
            
            let brief = projectBriefs[title] || fallbackText;
            
            document.getElementById('modalProjectTitle').innerText = title;
            document.getElementById('modalProjectIcon').innerHTML = iconHtml;
            document.getElementById('modalProjectTag').innerText = tag;
            document.getElementById('modalProjectBrief').innerHTML = brief;
            
            if(projectModal) projectModal.show();
        });
    });
});
